import{_ as a,o as i,c as s,a6 as n}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"Non-Validator Participation","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/networks/participation.md","filePath":"mainchain/networks/participation.md"}'),t={name:"mainchain/networks/participation.md"};function o(r,e,d,l,p,h){return i(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="non-validator-participation" tabindex="-1">Non-Validator Participation <a class="header-anchor" href="#non-validator-participation" aria-label="Permalink to &quot;Non-Validator Participation&quot;">​</a></h1><p>There are many ways in which users can contribute to the running of the network without the need to become a full validator.</p><h2 id="local-full-nodes" tabindex="-1">Local full-nodes <a class="header-anchor" href="#local-full-nodes" aria-label="Permalink to &quot;Local full-nodes&quot;">​</a></h2><p>One of the simplest ways to participate in the network is to run your own full node in which to send your own transactions to. Your node, by default, will only accept transactions sent to it from <code>localhost</code> before broadcasting them to its network peers, and is therefore a secure method by which to broadcast your transactions to the network. Further, by running your own local full node, transactions and their messages can be validated locally prior to being broadcast to network peers.</p><p>By default, your node&#39;s <code>P2P</code> address is not advertised, and its <code>RPC</code> is only accessible to the <code>localhost</code>.</p><p>This scenario is ideal for users who wish to infrequently spin up their node for the purpose of sending transactions to the network, or for users who are for example running a WRKChain, and wish to use the local node for broadcasting their WRKChain transactions.</p><p>Local full nodes can be run on your local PC, or server/cloud VMs alongside WRKChain architecture.</p><h2 id="seed-nodes" tabindex="-1">Seed Nodes <a class="header-anchor" href="#seed-nodes" aria-label="Permalink to &quot;Seed Nodes&quot;">​</a></h2><p>Seed nodes are used by full nodes to bootstrap their address book, by keeping a record of permanently connected nodes, and broadcasting their addresses on request. Seed nodes don&#39;t accept or broadcast transactions, and immediately disconnect from a peer once it has sent its address book to the connected peer.</p><p>Seed nodes are best run on servers/cloud VMs with high uptimes.</p><h3 id="configuring-a-seed-node" tabindex="-1">Configuring a seed node <a class="header-anchor" href="#configuring-a-seed-node" aria-label="Permalink to &quot;Configuring a seed node&quot;">​</a></h3><p>In <code>$HOME/.und_mainchain/config/config.toml</code>:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p2p.persistent_peers = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[node_id_1]@[ip_1]:[port],[node_id_2]@[ip_2]:[port]&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # List of peers known to the seed that are permanently available</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p2p.seed_mode = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>Seed nodes can also prune all data, by setting <code>pruning=everything</code> in <code>$HOME/.und_mainchain/config/app.toml</code>.</p><h2 id="archive-data-nodes" tabindex="-1">Archive/Data Nodes <a class="header-anchor" href="#archive-data-nodes" aria-label="Permalink to &quot;Archive/Data Nodes&quot;">​</a></h2><p>Archive nodes are full nodes that keep a complete history of the chain state, by not pruning any state data (i.e. <code>pruning</code> is set to <code>nothing</code> in <code>$HOME/.und_mainchain/app.toml</code>). They are used as the data source for third party applications such as block explorers and wallet apps, since they keep a complete event and transaction history.</p><p>Archive nodes are best run on servers/cloud VMs with high uptimes and large disk space.</p><h3 id="configuring-an-archive-node" tabindex="-1">Configuring an archive node <a class="header-anchor" href="#configuring-an-archive-node" aria-label="Permalink to &quot;Configuring an archive node&quot;">​</a></h3><p>In <code>$HOME/.und_mainchain/config/config.toml</code>, the following suggested settings offer a basic starting point. Users are encouraged to explore the settings and configure as required to increase security and availability:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p2p.external_address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[ip]:26656&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rpc.laddr = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tcp://0.0.0.0:26657&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tx_index.index_keys = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tx_index.index_all_keys = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>In <code>$HOME/.und_mainchain/config/app.toml</code>:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">minimum-gas-prices = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;25.0nund&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pruning = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nothing&quot;</span></span></code></pre></div><p>Ensure any firewall rules allow incoming requests to ports <code>26656</code> and <code>26657</code> from <code>0.0.0.0/0</code> - this will allow any clients to query your node.</p><h3 id="rest-server" tabindex="-1">REST server <a class="header-anchor" href="#rest-server" aria-label="Permalink to &quot;REST server&quot;">​</a></h3><p>A REST (light-client) server can be run alongside an Archive Node to offer deeper querying capabilities to the network. Third party applications such as block explorers and wallet apps rely on REST servers along with Archive nodes for their data.</p><p>REST servers are best run on servers/cloud VMs with high uptimes, along with an Archive node.</p><p>The REST server can be started by setting the configuring options in <code>app.toml</code> as follows:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">api</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">swagger = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tcp://0.0.0.0:1317&quot;</span></span></code></pre></div><h2 id="relay-nodes" tabindex="-1">Relay Nodes <a class="header-anchor" href="#relay-nodes" aria-label="Permalink to &quot;Relay Nodes&quot;">​</a></h2><p>A relay node is simply a full node that is always online and advertises its <code>P2P</code> network address to other peers. Relay nodes can potentially help reduce overall P2P network latency.</p><h3 id="configuring-a-relay-node" tabindex="-1">Configuring a Relay Node <a class="header-anchor" href="#configuring-a-relay-node" aria-label="Permalink to &quot;Configuring a Relay Node&quot;">​</a></h3><p>A relay node should have high availability (for example, be running on a Cloud VM, or other host that is always online with a static IP address).</p><p>In <code>$HOME/.und_mainchain/config/config.toml</code> set the <code>p2p.external_address</code> value to <code>0.0.0.0:26656</code>, and ensure any firewall rules allow incoming requests from <code>0.0.0.0/0</code> on port <code>26656</code></p><p>In <code>$HOME/.und_mainchin/config/app.toml</code> set the <code>minimum-gas-prices</code> value, to for example <code>25.0nund</code>.</p>`,34)])])}const g=a(t,[["render",o]]);export{u as __pageData,g as default};
